"""sklearn.random_projection — Random projection dimensionality reduction."""
import numpy as np
from sklearn.base import BaseEstimator, TransformerMixin


class GaussianRandomProjection(BaseEstimator, TransformerMixin):
    """Reduce dimensionality via Gaussian random projection.

    Parameters
    ----------
    n_components : int, default=100
    random_state : int or None, default=None
    """

    def __init__(self, n_components=100, random_state=None):
        self.n_components = n_components
        self.random_state = random_state

    def fit(self, X, y=None):
        rng = np.random.RandomState(self.random_state)
        n_features = np.asarray(X).shape[1]
        self.components_ = rng.normal(0, 1.0 / np.sqrt(self.n_components),
                                       size=(self.n_components, n_features))
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        return X @ self.components_.T


class SparseRandomProjection(BaseEstimator, TransformerMixin):
    """Reduce dimensionality via sparse random projection.

    Parameters
    ----------
    n_components : int, default=100
    density : float or 'auto', default='auto'
    random_state : int or None, default=None
    """

    def __init__(self, n_components=100, density='auto', random_state=None):
        self.n_components = n_components
        self.density = density
        self.random_state = random_state

    def fit(self, X, y=None):
        rng = np.random.RandomState(self.random_state)
        n_features = np.asarray(X).shape[1]
        if self.density == 'auto':
            density = 1.0 / np.sqrt(n_features)
        else:
            density = self.density

        # Achlioptas sparse random matrix
        s = 1.0 / density
        self.components_ = np.zeros((self.n_components, n_features))
        for i in range(self.n_components):
            for j in range(n_features):
                r = rng.random()
                if r < 1.0 / (2 * s):
                    self.components_[i, j] = np.sqrt(s)
                elif r < 1.0 / s:
                    self.components_[i, j] = -np.sqrt(s)
        self.components_ /= np.sqrt(self.n_components)
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        return X @ self.components_.T
